import datetime

def parse_ics(filepath):
    events = []
    with open(filepath, 'r') as f:
        lines = f.readlines()

    in_event = False
    start = None
    end = None

    for line in lines:
        line = line.strip()
        if line == 'BEGIN:VEVENT':
            in_event = True
            start = None
            end = None
        elif line == 'END:VEVENT':
            if start and end:
                events.append((start, end))
            in_event = False
        elif in_event and line.startswith('DTSTART:'):
            val = line.split(':')[1]
            start = datetime.datetime.strptime(val, '%Y%m%dT%H%M%SZ')
        elif in_event and line.startswith('DTEND:'):
            val = line.split(':')[1]
            end = datetime.datetime.strptime(val, '%Y%m%dT%H%M%SZ')
    return events

alice_events = parse_ics('/app/alice_calendar.ics')
bob_events = parse_ics('/app/bob_calendar.ics')
carol_events = parse_ics('/app/carol_calendar.ics')

# Business hours Jan 15-19, 2024
# Jan 15 is Monday.
days = [
    datetime.datetime(2024, 1, 15),
    datetime.datetime(2024, 1, 16),
    datetime.datetime(2024, 1, 17),
    datetime.datetime(2024, 1, 18),
    datetime.datetime(2024, 1, 19),
]

def is_available(t_start, t_end):
    # Hard constraints

    # Alice: no meetings after 2 PM (14:00) or before 9 AM (09:00)
    if t_start.hour < 9 or t_end.hour > 14 or (t_end.hour == 14 and t_end.minute > 0):
        return False

    # Bob: no meetings before 10 AM
    if t_start.hour < 10:
        return False

    # Bob: must leave by 4:30 PM on Tue/Thu
    # Jan 16 is Tue, Jan 18 is Thu
    if t_start.day in [16, 18]:
        if t_end.hour > 16 or (t_end.hour == 16 and t_end.minute > 30):
            return False

    # Carol: Lunch 12:00-12:30 (unavailable)
    lunch_start = t_start.replace(hour=12, minute=0)
    lunch_end = t_start.replace(hour=12, minute=30)
    if t_start < lunch_end and t_end > lunch_start:
        return False

    # Carol: Needs 15-min buffer after meetings ending at 4:45 PM or later
    # (Since Alice's constraint limits to 14:00, this won't be hit, but implement anyway)
    # The requirement is that Carol is available for the 15 mins after.
    # Her working hours are until 17:00.
    if t_end.hour >= 17 or (t_end.hour == 16 and t_end.minute >= 45):
        buffer_end = t_end + datetime.timedelta(minutes=15)
        # Check if buffer_end is after 17:00
        if buffer_end.hour >= 17 and buffer_end.minute > 0:
            return False

    # Check overlap with existing events
    for e_start, e_end in alice_events:
        if t_start < e_end and t_end > e_start:
            return False

    for e_start, e_end in bob_events:
        if t_start < e_end and t_end > e_start:
            return False

    for e_start, e_end in carol_events:
        if t_start < e_end and t_end > e_start:
            return False

    return True

valid_slots = []
for day in days:
    # Try every minute from 09:00 to 17:00
    current = day.replace(hour=9, minute=0)
    end_of_day = day.replace(hour=18, minute=0)

    while current + datetime.timedelta(hours=1) <= end_of_day:
        t_start = current
        t_end = current + datetime.timedelta(hours=1)
        if is_available(t_start, t_end):
            valid_slots.append((t_start, t_end))
        current += datetime.timedelta(minutes=1)

for slot in valid_slots:
    print(slot[0].strftime("%Y-%m-%d %H:%M"), "-", slot[1].strftime("%H:%M"))

